# WRONG: mask is set once at init but overwritten by gradients
class BrokenMaskedConv(nn.Module):
    def __init__(self, in_ch, out_ch):
        super().__init__()
        self.conv = nn.Conv2d(in_ch, out_ch, 3, padding=1)
        mask = build_mask(out_ch, in_ch)
        self.conv.weight.data *= mask
        # After optimizer.step(), the masked weights are no longer zero

# CORRECT: register mask as buffer and apply in forward
class CorrectMaskedConv(nn.Module):
    def __init__(self, in_ch, out_ch, mask_type='B'):
        super().__init__()
        self.conv = nn.Conv2d(in_ch, out_ch, 3, padding=1)
        mask = build_mask(out_ch, in_ch, mask_type)
        self.register_buffer('mask', mask)  # saved with state_dict

    def forward(self, x):
        self.conv.weight.data *= self.mask   # reapply before each forward
        return self.conv(x)
